#include <OneWire.h>
#include <DallasTemperature.h>
#include <SD.h>
#define OW_PIN 2
#define FLOW_PIN 3
#define PUMP_RELAY 7
#define SD_CS 10
#define LOG_INTERVAL 5000UL
OneWire ow(OW_PIN); DallasTemperature ds(&ow); File lg;
volatile unsigned int flowPulses=0;
void IRAM flowISR(){flowPulses++;}
float ntu_effectiveness_calc(float Thin,float Thout,float Tcin,float Tcout,float*NTU){
  float dTmax=Thin-Tcin; if(dTmax<0.5f){*NTU=0;return 0;}
  float eps=constrain((Thin-Thout)/dTmax,0.0f,0.999f);
  *NTU=-log(1.0f-eps); return eps;
}
void initHardware(){
  ds.begin();pinMode(FLOW_PIN,INPUT_PULLUP);pinMode(PUMP_RELAY,OUTPUT);
  attachInterrupt(digitalPinToInterrupt(FLOW_PIN),flowISR,RISING);
  SD.begin(SD_CS);lg=SD.open("hx.csv",FILE_WRITE);
  if(lg)lg.println("t_s,Thin,Thout,Tcin,Tcout,Lmin,eps,NTU");
  digitalWrite(PUMP_RELAY,HIGH);Serial.begin(9600);
}
void readAllTemperatures(float*Thin,float*Thout,float*Tcin,float*Tcout){
  ds.requestTemperatures();
  *Thin=ds.getTempCByIndex(0);*Thout=ds.getTempCByIndex(1);
  *Tcin=ds.getTempCByIndex(2);*Tcout=ds.getTempCByIndex(3);
}
void checkFaultSafety(float Thin,float Thout,float Tcin){
  if(Thout<Tcin){digitalWrite(PUMP_RELAY,LOW);Serial.println("FAULT:CROSSOVER");while(1);}
  if(Thin>85.0f){digitalWrite(PUMP_RELAY,LOW);Serial.println("FAULT:OVERTEMP");while(1);}
}
void logDataSD(unsigned long t,float Thin,float Thout,float Tcin,float Tcout,float flow,float eps,float NTU){
  if(lg){lg.print(t);lg.print(',');lg.print(Thin,2);lg.print(',');lg.print(Thout,2);lg.print(',');
  lg.print(Tcin,2);lg.print(',');lg.print(Tcout,2);lg.print(',');
  lg.print(flow,3);lg.print(',');lg.print(eps,4);lg.print(',');lg.println(NTU,4);lg.flush();}
  Serial.print("eps=");Serial.print(eps,4);Serial.print(" NTU=");Serial.println(NTU,4);
}
void setup(){initHardware();}
void loop(){
  static unsigned long prev=0;unsigned long now=millis();
  if(now-prev<LOG_INTERVAL)return;float dt=(now-prev)/1000.0f;prev=now;
  float Thin,Thout,Tcin,Tcout;
  readAllTemperatures(&Thin,&Thout,&Tcin,&Tcout);
  checkFaultSafety(Thin,Thout,Tcin);
  noInterrupts();unsigned int p=flowPulses;flowPulses=0;interrupts();
  float flow=p/(7.5f*dt);
  float NTU=0;float eps=ntu_effectiveness_calc(Thin,Thout,Tcin,Tcout,&NTU);
  logDataSD(now/1000,Thin,Thout,Tcin,Tcout,flow,eps,NTU);
}
